import{_ as t,o as i,c as h,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Phân quyền","description":"","frontmatter":{"title":"Phân quyền"},"headers":[],"relativePath":"permissions.md","filePath":"permissions.md"}'),o={name:"permissions.md"};function a(g,n,u,c,s,e){return i(),h("div",null,[...n[0]||(n[0]=[r('<h1 id="phan-quyen" tabindex="-1">Phân quyền <a class="header-anchor" href="#phan-quyen" aria-label="Permalink to &quot;Phân quyền&quot;">​</a></h1><p>Mô-đun <strong>Phân quyền (Permissions)</strong> trong ABNERP cung cấp hệ thống kiểm soát truy cập linh hoạt và chi tiết, cho phép quản trị viên xác định chính xác ai có thể xem, tạo, sửa, xóa hoặc phê duyệt từng loại dữ liệu trong hệ thống.</p><h2 id="phan-quyen-dua-tren-vai-tro" tabindex="-1">Phân quyền dựa trên vai trò <a class="header-anchor" href="#phan-quyen-dua-tren-vai-tro" aria-label="Permalink to &quot;Phân quyền dựa trên vai trò&quot;">​</a></h2><p><strong>Phân quyền dựa trên vai trò (Role-Based Permissions)</strong> là phương pháp quản lý quyền truy cập cốt lõi trong ABNERP. Mỗi người dùng được gán một hoặc nhiều <strong>vai trò (Role)</strong>, và mỗi vai trò có một bộ quyền hạn cụ thể. Hệ thống cung cấp sẵn các vai trò mặc định như:</p><ul><li><strong>Administrator</strong>: toàn quyền trên toàn hệ thống</li><li><strong>System Manager</strong>: quản lý cài đặt hệ thống và người dùng</li><li><strong>Accounts Manager</strong>: quản lý các nghiệp vụ kế toán</li><li><strong>Sales Manager</strong>: quản lý hoạt động bán hàng</li><li><strong>Purchase Manager</strong>: quản lý hoạt động mua hàng</li><li><strong>Employee</strong>: quyền cơ bản cho nhân viên</li><li><strong>Customer</strong>: quyền cho khách hàng truy cập cổng thông tin</li></ul><p>Người dùng có thể tạo vai trò mới và tùy chỉnh quyền cho từng vai trò một cách linh hoạt.</p><h2 id="phan-quyen-nguoi-dung" tabindex="-1">Phân quyền người dùng <a class="header-anchor" href="#phan-quyen-nguoi-dung" aria-label="Permalink to &quot;Phân quyền người dùng&quot;">​</a></h2><p><strong>Phân quyền người dùng (User Permissions)</strong> cho phép kiểm soát ở mức chi tiết hơn ngoài quyền vai trò. Các loại quyền bao gồm:</p><ul><li><strong>Quyền Chi nhánh</strong>: giới hạn người dùng chỉ được thao tác dữ liệu thuộc chi nhánh của mình</li><li><strong>Quyền Tài liệu</strong>: kiểm soát quyền truy cập đến từng tài liệu cụ thể</li><li><strong>Quyền Trường</strong>: kiểm soát quyền xem/sửa đến từng trường dữ liệu</li><li><strong>Quyền Theo bản ghi</strong>: cho phép hoặc từ chối truy cập đến các bản ghi riêng lẻ</li></ul><p>Ví dụ: một nhân viên bán hàng có thể xem và tạo đơn hàng (quyền vai trò), nhưng chỉ được xem đơn hàng của riêng mình (quyền người dùng).</p><h2 id="quan-ly-phan-quyen" tabindex="-1">Quản lý phân quyền <a class="header-anchor" href="#quan-ly-phan-quyen" aria-label="Permalink to &quot;Quản lý phân quyền&quot;">​</a></h2><p><strong>Quản lý phân quyền (Permission Management)</strong> bao gồm các công cụ và quy tắc để quản trị viên thiết lập, theo dõi và kiểm tra hệ thống phân quyền:</p><ul><li><strong>Công cụ cấp quyền trực quan</strong>: giao diện dạng bảng cho phép thiết lập quyền nhanh chóng</li><li><strong>Mức quyền (Permission Levels)</strong>: quyền Read, Write, Create, Delete, Submit, Amend, Cancel, Share</li><li><strong>Quy tắc kế thừa</strong>: quyền có thể được kế thừa từ cha (ví dụ: quyền trên Báo giá được kế thừa từ Đơn hàng)</li><li><strong>Kiểm tra quyền</strong>: công cụ cho phép kiểm tra quyền của một người dùng trên một tài liệu cụ thể</li><li><strong>Nhật ký thay đổi</strong>: ghi nhận mọi thay đổi phân quyền trong hệ thống</li></ul><p>Hệ thống phân quyền đảm bảo tính bảo mật và kiểm soát dữ liệu chặt chẽ, phù hợp với các doanh nghiệp có nhiều cấp độ quản lý và yêu cầu phân tách nhiệm vụ rõ ràng.</p>',14)])])}const q=t(o,[["render",a]]);export{p as __pageData,q as default};
